class Solution:
    def binaryGap(self, n: int) -> int:
        ones = []
        pos = 0
        while n:
            if n & 1:
                ones.append(pos)
            n >>= 1
            pos += 1
        if len(ones) < 2:
            return 0
        max_dist = 0
        for i in range(1, len(ones)):
            max_dist = max(max_dist, ones[i] - ones[i-1])
        return max_dist

